import React, { useEffect, useState } from 'react'
import logo2 from '../images/logo2.png'
import logo1 from '../images/logo1.png'
import logo from '../images/logo.png'
import urslogo from '../images/urslogo.png'
import { Box, Button, Container, TextField, Link, Typography, Fade } from '@material-ui/core';
import { makeStyles } from '@material-ui/styles';

const useStyle = makeStyles(theme => {
    return {
    root: {
        '& .MuiInputBase-root': {
            marginBottom: theme.spacing(1)
        },
        '& .MuiInputBase-input': {
            padding: theme.spacing(2)
        },
        '& .MuiLink-root': {
            color: '#162276',
        }
    },
    formContainer: {
        display: 'fixed',
        backgroundColor: '#f9fbfd',
        padding: '22px',
        [theme.breakpoints.up('sm')]: {
            display: 'block',
            boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',
            maxWidth: '400px',
            borderRadius: '7px',
            marginTop: '10%',
            paddingBottom: '30px',
            backgroundColor: '#ffffff'
        }
    },
    logoContainer: {
        maxWidth: '300px',
        margin: '0 auto'
    },
    logo: {
        width: '100%',
        paddingTop: '10%'
    },
    responsiveLogo: {
        display: 'none',
        [theme.breakpoints.up('md')]: {
            display: 'block'
        }
    },
    responsiveLogo1: {
        display: 'none',
        [theme.breakpoints.only('sm')]: {
            display: 'block'
        }
    },
    responsiveLogo2: {
        display: 'none',
        [theme.breakpoints.down('xs')]: {
            display: 'block'
        }
    },
    form: {
        margin: '0 auto',
        maxWidth: '350px'
    },
    btn: {
        width: '100%',
        margin: '12px 0'
    },
    loading: {
        display: 'flex',
        height: '100%',
        width: '100%',
        zIndex: 1,
        position: 'absolute',
        background: '#f9fbfd',
        top: '-40px'
    },
    loadingImage: {
        width: '200px', 
        margin: 'auto'
    }

}});

export default function Login() {

    const [isPending, setIsPending] = useState(true);

  useEffect(() => {
    setTimeout(() => {
      fetch('http://localhost:3000/')
      .then(data => {
        setIsPending(false);
      })
    }, 3000);
  }, [])

  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setTimeout(() => {
      fetch('http://localhost:3000/')
      .then(data => {
        setIsLoading(false);
      })
    }, 3001);
  }, [])


    const classes = useStyle();
    return (
        <Box className={classes.root}>
            
            { isPending && 
            <Fade in='true' >
                <div className={classes.loading}>
                    <img src={urslogo} className={classes.loadingImage} />
                </div>
            </Fade>
            }
            { isLoading &&
            <Fade in='true'>
            <Container className={classes.formContainer}>
                <div className={classes.logoContainer}>
                <Box className={classes.responsiveLogo}>
                        <img className={classes.logo} src={logo} alt="URSAC Online logo" />
                    </Box>
                    <Box className={classes.responsiveLogo1}>
                        <img className={classes.logo} src={logo1} alt="URSAC Online logo" />
                    </Box>
                    <Box className={classes.responsiveLogo2}>
                        <img className={classes.logo} src={logo2} alt="URSAC Online logo" />
                    </Box>
                </div>
                <div className={classes.form}>
                    <TextField placeholder='Student ID' variant='outlined' fullWidth />
                    <TextField placeholder='Password' variant='outlined' type='password' fullWidth />
                    <Button className={classes.btn} href='/studentDashboard' size='large' variant='contained' color='secondary'>
                        LOGIN
                    </Button>
                    <center>
                        <div>
                            <Typography variant='caption'>
                                <Link href="#">
                                    Forgot Password?
                                </Link>
                            </Typography>
                        </div>
                        <div>
                            <Typography variant='caption'>
                                <Link href='/TeacherDashboard'>
                                    Teacher Login.
                                </Link>
                            </Typography>
                        </div>
                    </center>
                </div>
            </Container>
            </Fade>
            }
        </Box>
    )
}
